sql:
SELECT balance_factor, last_reviewed, notes, reviewed_by, review_frequency 
FROM item_balancing 
WHERE item_id = 0;

SELECT item_id
FROM item_balancing
WHERE balance_factor > (SELECT AVG(balance_factor) FROM item_balancing);

SELECT i.name
FROM items i
WHERE i.quality = (
    SELECT MAX(quality)
    FROM items
);

